import sys
import re


def input():
    return sys.stdin.readline().strip()


n = int(input())
s = input().split()
d = dict()
for i in range(int(input())):
    a, b = input().split()
    d[a.lower()] = b
for i in range(n):
    s[i] = re.sub(r'[a-zA-Z]', lambda x: d.get(x.group().lower(), x.group()), s[i])
print(min(s, key=lambda x: x.count('r')), len(min(s, key=lambda x: x.count('r'))))
